  ('cpa-moex-01393', 'cpa', 'cpa-moex-103-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '向興公司的某事業部資料如下：營收$640,000，變動費用$160,000，固定費用$300,000，加權平均 資金成本12%，公司之所得稅率40%。假設該事業部的長期資本（固定資產＋營運資金）是$800,000， 其經濟附加價值（economic value added, EVA）是多少？', '["$12,000", "$96,000", "$108,000", "$180,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "931ef34bb028", "answer_pdf_sha1": "0115394f7ee8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
